import { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { RichTextEditor } from "@/components/admin/RichTextEditor";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Save, Loader2, Eye, Upload, X } from "lucide-react";
import taijiIcon from "@/assets/taiji.svg";

const AdminCertification = () => {
  const { t } = useTranslation();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [contentId, setContentId] = useState<string | null>(null);
  const [contentZh, setContentZh] = useState("");
  const [ichingText, setIchingText] = useState("");
  const [certificationVideoUrl, setCertificationVideoUrl] = useState("");
  const [uploadingVideo, setUploadingVideo] = useState(false);

  useEffect(() => {
    fetchContent();
  }, []);

  const fetchContent = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from("certification_content" as any)
      .select("*")
      .limit(1)
      .single();

    if (data) {
      setContentId((data as any).id);
      setContentZh((data as any).content_zh || "");
      setIchingText((data as any).iching_text || "");
      setCertificationVideoUrl((data as any).certification_video_url || "");
    }
    if (error) console.error("Error fetching certification content:", error);
    setLoading(false);
  };

  const handleSave = async () => {
    if (!contentId) return;
    setSaving(true);
    const { error } = await supabase
      .from("certification_content" as any)
      .update({
        content_zh: contentZh,
        content_en: contentZh,
        content_pt: contentZh,
        iching_text: ichingText,
        certification_video_url: certificationVideoUrl || null,
        updated_at: new Date().toISOString(),
      } as any)
      .eq("id", contentId);

    if (error) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } else {
      toast({ title: t("common.success"), description: t("common.actions.saved", "已保存") });
    }
    setSaving(false);
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">{t("admin.certification", "认证")}</h1>
          <p className="text-muted-foreground text-sm mt-1">
            编辑「认证」页面内容（单语言输入，前端自动翻译）
          </p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => window.open("/certification", "_blank")}>
            <Eye className="w-4 h-4 mr-2" />
            {t("common.preview", "预览")}
          </Button>
          <Button onClick={handleSave} disabled={saving}>
            {saving ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
            {t("common.actions.save")}
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg">📝 主体内容</CardTitle>
          <CardDescription>认证页面的主要介绍（前端会自动翻译为用户的语言）</CardDescription>
        </CardHeader>
        <CardContent>
          <RichTextEditor
            value={contentZh}
            onChange={setContentZh}
            placeholder="输入认证页面的内容..."
            className="min-h-[400px]"
            enableImageUpload
          />
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">🎬 认证视频</CardTitle>
          <CardDescription>上传或输入视频链接，将在认证页面显示播放按钮</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label>视频文件上传</Label>
            <div className="flex gap-2">
              <Input
                type="file"
                accept="video/*"
                className="hidden"
                id="certification-video-upload"
                onChange={async (e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;
                  if (file.size > 50 * 1024 * 1024) {
                    toast({ title: "文件过大", description: "视频最大50MB", variant: "destructive" });
                    return;
                  }
                  setUploadingVideo(true);
                  const ext = file.name.split(".").pop();
                  const path = `certification/certification-video-${Date.now()}.${ext}`;
                  const { error } = await supabase.storage.from("promo-images").upload(path, file, { upsert: true });
                  if (error) {
                    toast({ title: "上传失败", description: error.message, variant: "destructive" });
                  } else {
                    const { data: urlData } = supabase.storage.from("promo-images").getPublicUrl(path);
                    setCertificationVideoUrl(urlData.publicUrl);
                    toast({ title: "上传成功" });
                  }
                  setUploadingVideo(false);
                }}
              />
              <Button
                variant="outline"
                size="sm"
                disabled={uploadingVideo}
                onClick={() => document.getElementById("certification-video-upload")?.click()}
              >
                {uploadingVideo ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Upload className="w-4 h-4 mr-2" />}
                上传视频
              </Button>
            </div>
          </div>
          <div className="space-y-2">
            <Label>或输入视频链接</Label>
            <Input
              value={certificationVideoUrl}
              onChange={(e) => setCertificationVideoUrl(e.target.value)}
              placeholder="https://... 视频链接"
            />
          </div>
          {certificationVideoUrl && (
            <div className="space-y-2">
              <Label>预览</Label>
              <div className="relative rounded-lg overflow-hidden bg-black max-w-md">
                <video src={certificationVideoUrl} controls className="w-full max-h-[240px]" />
                <Button
                  variant="destructive"
                  size="icon"
                  className="absolute top-2 right-2 h-7 w-7"
                  onClick={() => setCertificationVideoUrl("")}
                >
                  <X className="w-4 h-4" />
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">☰ 易经解读 <img src={taijiIcon} alt="太极" className="h-5 w-5 inline-block" /></CardTitle>
          <CardDescription>默认显示中文，用户可点击翻译按钮手动翻译</CardDescription>
        </CardHeader>
        <CardContent>
          <Textarea
            value={ichingText}
            onChange={(e) => setIchingText(e.target.value)}
            placeholder="输入易经解读内容，例如：《易经·乾》：..."
            className="min-h-[200px] font-serif"
            rows={8}
          />
        </CardContent>
      </Card>
    </div>
  );
};

export default AdminCertification;
